import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v11 (Judaism - institutions) ===');

w('profiles_v11','chabad-lubavitch',{"brand_name":"Chabad-Lubavitch","brand_slug":"chabad-lubavitch","parent_company":"Chabad-Lubavitch World Headquarters","ultimate_parent":"Chabad-Lubavitch (de facto leaderless since Rebbe's death 1994)","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"CHABAD HAS 5,000 CENTERS IN 100 COUNTRIES AND NO CENTRAL FINANCIAL OVERSIGHT — SOME FOLLOWERS BELIEVE THE REBBE WHO DIED IN 1994 IS THE MESSIAH AND WILL RETURN — AND ITS AUSTRALIA BRANCH COVERED UP SEXUAL ABUSE FOR DECADES","executive_summary":"Chabad-Lubavitch is a Hasidic Jewish movement founded in 18th century Russia and now headquartered at 770 Eastern Parkway in Crown Heights, Brooklyn. It operates approximately 5,000 centers in over 100 countries — the most geographically dispersed Jewish outreach network in the world. Since the death of its seventh Rebbe, Menachem Mendel Schneerson, in 1994, Chabad has operated without a recognized successor — a unique organizational structure where thousands of semi-autonomous emissary couples (shluchim) operate individual Chabad Houses with significant local independence and minimal central financial oversight. A significant minority of Chabad members and leaders believe Schneerson was the Messiah and will return — a belief (meshichism) that has caused internal divisions. Chabad Australia was the subject of a major sexual abuse scandal documented by the Australian Royal Commission into Institutional Responses to Child Sexual Abuse — finding that Chabad institutions in Australia failed to report abuse and handled allegations in ways that protected abusers.","verdict_tags":["5000_centers_100_countries_no_central_oversight","australian_royal_commission_abuse_cover_up","meshichist_messiah_belief_rebbe_1994","shluchim_semi_autonomous_financial_opacity","crown_heights_brooklyn_headquarters","schneerson_death_no_successor","political_influence_global_documented"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Chabad shluchim (emissary couples) are essentially self-employed small business operators running their own Chabad Houses — they fundraise independently, employ local staff, and operate with significant autonomy. This model creates both entrepreneurial flexibility and accountability gaps. No major documented systemic labor violations have been identified at the movement level.","flags":["shluchim_self_employed_independent_fundraising","autonomous_model_accountability_gaps"],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for Chabad-Lubavitch at the movement level.","flags":[],"sources":[]},"political":{"summary":"Chabad's global network gives it extraordinary political access — Chabad rabbis serve as the primary Jewish institutional presence in dozens of countries where there is no other significant Jewish community. This access has been documented in relationships with political leaders from Vladimir Putin (who has had documented positive relationships with Russian Chabad leadership) to multiple US presidents. Chabad's non-proselytizing outreach model — welcoming any Jew regardless of observance — gives it broad cross-denominational Jewish political relationships. The movement's political positions align with Orthodox Jewish consensus: support for Israel, opposition to anti-Semitism, support for Jewish continuity programs.","flags":["putin_russian_chabad_documented_relationship","presidential_access_multiple_countries","orthodox_political_consensus_alignment"],"sources":[]},"legal":{"summary":"Australian Royal Commission into Institutional Responses to Child Sexual Abuse: The Commission examined Chabad institutions in Australia and found documented failures to report abuse and handling of allegations that protected abusers. Rabbi Zelig Serebryanski — a prominent Melbourne Chabad figure — was documented as having been protected by community leaders despite abuse allegations. The Commission's findings regarding Chabad Australia were consistent with its broader findings about Orthodox Jewish institutions' use of rabbinic authority to discourage external reporting. In the United States, multiple Chabad rabbis have been convicted of sexual abuse; the organizational structure's decentralization has made institutional accountability difficult to establish.","flags":["australian_royal_commission_abuse_cover_up","serebryanski_protected_documented","us_multiple_rabbis_convicted_decentralized_accountability","reporting_discouraged_rabbinic_authority"],"sources":["https://www.childabuseroyalcommission.gov.au"]},"tax":{"summary":"Chabad-Lubavitch World Headquarters and individual Chabad Houses are tax-exempt religious organizations. The decentralized structure — where each Chabad House is a separate entity — means there is no consolidated financial disclosure for the movement as a whole. Individual Chabad Houses file their own Form 990s (if required) but the movement's total financial scale is not publicly known. Estimates of Chabad's global budget range from hundreds of millions to over a billion dollars annually.","flags":["no_consolidated_financial_disclosure","individual_houses_separate_entities","total_scale_unknown","hundreds_millions_to_billion_estimated"],"sources":[]},"executives":{"summary":"Menachem Mendel Schneerson — the seventh Lubavitcher Rebbe — died in June 1994 without designating a successor. The movement has operated without a recognized leader since. The meshichist faction believes Schneerson is the Messiah and will return; this belief is held by a significant minority of Chabad institutions globally and by a majority of some Chabad centers. Rabbi Moshe Kotlarsky leads the Chabad-Lubavitch International Shluchim Office — the closest thing to a central coordinating body — but has no authority over individual Chabad Houses. Kushner family connections: Jared Kushner has documented Chabad affiliation; the Kushner family's relationship with Chabad has generated political commentary about the movement's proximity to US political power.","flags":["schneerson_died_1994_no_successor","meshichist_faction_significant_minority","kotlarsky_coordinating_no_authority","kushner_chabad_political_commentary"],"sources":[]},"connections":{"summary":"Chabad's global network creates documented political relationships that no other Jewish organization can match — in countries from South Africa to Thailand to Russia, the Chabad shliach is often the first and only Jewish institutional contact for visiting heads of state and business figures. The movement's relationship with Russian Jewish oligarchs — who have funded many Chabad Houses globally — creates documented financial connections to post-Soviet wealth.","flags":["unique_global_political_access","russian_jewish_oligarch_funding_documented","post_soviet_wealth_connections"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The Australian Royal Commission documented that Chabad's rabbinic authority structures discouraged victims from reporting abuse to secular authorities — consistent with the broader Orthodox Jewish mesirah (informing) doctrine that some authorities use to discourage reporting to non-Jewish legal systems. Critics have alleged that Chabad's decentralized structure is specifically advantageous for avoiding institutional accountability for abuse — that individual houses can distance themselves from convicted rabbis without the movement bearing institutional responsibility. Chabad disputes this characterization.",
"flags":["mesirah_doctrine_reporting_discouragement_alleged","decentralization_accountability_avoidance_alleged"],"sources":["https://www.childabuseroyalcommission.gov.au"]},"health_record":{"summary":"The Australian Royal Commission documented specific cases of sexual abuse within Chabad institutions in Australia and found that institutional responses prioritized community reputation over victim welfare — consistent with the Commission's findings across multiple Jewish and non-Jewish religious institutions. Multiple Chabad rabbis in the United States have been convicted of sexual abuse of minors and adults; the decentralized structure has complicated institutional accountability.","flags":["australia_royal_commission_abuse_documented","us_multiple_convictions_decentralized_accountability","reputation_over_victim_welfare_finding"],"sources":["https://www.childabuseroyalcommission.gov.au"]},"alternatives":{"cheaper":["Reform, Conservative, and Reconstructionist synagogues — different Jewish denominational traditions with varying institutional structures","Independent minyanim — self-organized prayer communities without institutional hierarchy"],"healthier":["Jewish communities with published safeguarding policies and external reporting protocols","Synagogues affiliated with denominations with centralized accountability mechanisms"],"diy":["Australian Royal Commission Case Study findings on Jewish institutions are publicly available","Individual Chabad House Form 990s are available through ProPublica Nonprofit Explorer where filed"]},"timeline":[{"year":1775,"event":"Shneur Zalman of Liadi founds Chabad Hasidic movement in Belarus","severity":"neutral","source_url":""},{"year":1940,"event":"Sixth Rebbe Yosef Yitzchak Schneersohn relocates Chabad headquarters to Crown Heights, Brooklyn from Nazi-occupied Europe","severity":"neutral","source_url":""},{"year":1951,"event":"Menachem Mendel Schneerson becomes seventh Rebbe; begins global shluchim expansion program","severity":"neutral","source_url":""},{"year":1994,"event":"Schneerson dies without successor; meshichist faction declares him Messiah; movement continues without recognized leader","severity":"high","source_url":""},{"year":2015,"event":"Australian Royal Commission examines Chabad institutions; documents abuse cover-up and reporting discouragement","severity":"critical","source_url":"https://www.childabuseroyalcommission.gov.au"},{"year":2017,"event":"Multiple Chabad rabbis in US face criminal proceedings for sexual abuse","severity":"critical","source_url":""}],"community_impact":{"displacement":"Sexual abuse victims within Chabad institutions — particularly in Australia — who reported abuse to community leaders found their reports handled internally in ways that protected abusers and discouraged external reporting. The Royal Commission documented these outcomes.","price_illusion":"Chabad presents as a warm, non-judgmental Jewish outreach movement welcoming any Jew regardless of observance or background. The institutional accountability gap created by decentralization means abuse within individual Chabad Houses is handled at the local level without movement-wide oversight.","tax_math":"Each Chabad House is a separate tax-exempt entity — meaning the movement's total financial scale is invisible in the public record. Estimates suggest Chabad's global budget may exceed a billion dollars annually, operating with no consolidated disclosure.","wealth_velocity":"Russian Jewish oligarch funding of Chabad Houses globally — documented in multiple journalistic investigations — connects post-Soviet wealth to religious institution building without transparent financial disclosure."},"cost_absorption":{"who_benefited":[{"group":"Chabad movement","how":"5,000 centers in 100 countries built through semi-autonomous shluchim model with no central financial accountability; extraordinary political access globally"}],"who_paid":[{"group":"Sexual abuse victims in Chabad institutions","how":"Australian Royal Commission documented abuse cover-up; reporting discouraged; institutional accountability gap from decentralization"}],"the_gap":"Chabad has 5,000 centers in 100 countries. There is no central financial disclosure. Each house is a separate entity. The seventh Rebbe died in 1994 and some followers believe he is the Messiah and will return. The Australian Royal Commission found Chabad institutions covered up abuse and discouraged reporting. Multiple Chabad rabbis in the US have been convicted of abuse. The decentralized structure makes institutional accountability nearly impossible to establish. That structure is also why it grew so fast."}});

w('profiles_v11','haredi-orthodox-sector',{"brand_name":"Haredi Orthodox Sector","brand_slug":"haredi-orthodox-sector","parent_company":"Multiple autonomous communities (sector profile)","ultimate_parent":"No single entity — sector analysis","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"ULTRA-ORTHODOX COMMUNITIES USE A DOCTRINE CALLED MESIRAH TO DISCOURAGE REPORTING ABUSE TO POLICE — NECHEMYA WEBERMAN WAS CONVICTED OF 59 COUNTS AFTER COMMUNITY MEMBERS THREATENED HIS VICTIM AND RAISED $500,000 FOR HIS DEFENSE","executive_summary":"Haredi (ultra-Orthodox) Judaism encompasses multiple distinct communities — including Satmar, Bobov, Ger, Belz, and dozens of other Hasidic courts, as well as non-Hasidic Litvish/Yeshivish communities — united by strict Orthodox observance, rejection of secular modernity, high birth rates, and insular community structures. The sector's documented institutional problem is the application of mesirah — a traditional Jewish legal concept historically prohibiting Jews from informing on fellow Jews to potentially hostile non-Jewish authorities — to discourage reporting of sexual abuse, financial crimes, and other misconduct to contemporary law enforcement. In 2012, Nechemya Weberman — a prominent Brooklyn Satmar community figure who worked as an unlicensed therapist — was convicted of 59 counts of sexual abuse of a young woman he had counseled. Community members organized a fundraising dinner raising approximately $500,000 for his defense, attempted to intimidate the victim, and were themselves prosecuted for witness tampering.","verdict_tags":["mesirah_doctrine_abuse_reporting_discouraged","weberman_59_counts_500k_fundraiser_defense","victim_intimidation_witness_tampering_prosecuted","yeshiva_tax_funded_services_controversy","boys_education_secular_subjects_minimal","new_york_yeshiva_education_investigations","australian_royal_commission_orthodox_findings","brooklyn_da_investigations_ongoing"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"Haredi communities operate extensive parallel institutions — schools, courts (batei din), social services — largely outside mainstream secular regulatory frameworks. Employment within Haredi-controlled institutions operates under community norms rather than standard labor law in some documented cases. No major documented systemic labor violations at the sector level have been identified beyond the educational controversy.","flags":["parallel_institutions_outside_regulatory_framework","employment_community_norms_documented"],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for the Haredi sector.","flags":[],"sources":[]},"political":{"summary":"Haredi communities exercise substantial political influence in New York City and State through bloc voting — delivering highly cohesive electoral support in exchange for political accommodations. These accommodations have included: exemptions from secular education requirements for yeshivas, public funding for private religious school busing and services, and documented political pressure on prosecutors to limit prosecution of community members. In Israel, Haredi political parties (UTJ and Shas) are perennial coalition partners whose leverage has secured: exemption from military service for yeshiva students, significant public funding for Haredi institutions, and control over religious affairs including conversion, marriage, and divorce.","flags":["bloc_voting_political_accommodations_documented","yeshiva_secular_education_exemption_ny","israel_military_service_exemption_documented","shas_utj_coalition_leverage_israel"],"sources":[]},"legal":{"summary":"Nechemya Weberman (2012): Convicted of 59 counts of sexual abuse of a minor he was counseling as an unlicensed therapist in the Satmar community of Brooklyn. Community members organized a fundraising dinner raising approximately $500,000 for his defense. Three men were subsequently convicted of intimidating the victim. Weberman was sentenced to 103 years. New York yeshiva education: New York City and State investigations have found that many Haredi yeshivas provide minimal or no secular education — potentially violating compulsory education laws — while receiving millions in public funds for busing and services. Brooklyn DA investigations: successive Brooklyn DAs have investigated multiple cases of abuse within Haredi communities with documented challenges from community pressure.","flags":["weberman_103_years_59_counts","500k_fundraiser_community_defense","three_convicted_victim_intimidation","nyc_yeshiva_secular_education_investigation","brooklyn_da_community_pressure_documented"],"sources":["https://www.nytimes.com/2012/12/10/nyregion/nechemya-weberman-sexual-abuse-trial-verdict.html"]},"tax":{"summary":"Haredi institutions — schools, synagogues, and social service organizations — are tax-exempt religious entities. New York State provides millions in public funds for yeshiva busing, special education services, and other programs serving Haredi students — public funding that has continued despite documented investigations into the adequacy of secular education in those schools. The intersection of public funding and inadequate secular education compliance represents a documented accountability gap.","flags":["public_funds_busing_services_documented","yeshiva_secular_education_noncompliance_public_funding","tax_exempt_institutions_parallel_system"],"sources":[]},"executives":{"summary":"The Haredi sector is governed by multiple grand rabbis (Rebbes in Hasidic communities, Rosh Yeshivas in Litvish communities) who exercise significant authority over their followers' lives. The Satmar Rebbe — currently divided between two brothers (Williamsburg and Kiryas Joel factions) — leads one of the largest and most insular Hasidic communities. Community rabbinical leaders have been documented making statements discouraging cooperation with law enforcement in abuse cases. Rabbi Shmuel Kamenetzky of Philadelphia — a senior Agudath Israel leader — was documented in the New York Times for providing a rabbinic letter supporting a parent who abducted children to Israel rather than comply with a US court custody order.","flags":["satmar_rebbe_split_two_brothers","community_leaders_discourage_law_enforcement_documented","kamenetzky_abduction_support_nyt"],"sources":[]},"connections":{"summary":"Agudath Israel of America — the primary political lobbying organization for Haredi interests in the United States — has lobbied against mandatory reporting laws that would require rabbis to report abuse to civil authorities, against statute of limitations extensions for abuse claims, and for political accommodations for yeshiva education standards. The organization's political relationships have been documented in New York City and Albany where Haredi bloc voting is a significant electoral factor.","flags":["agudath_israel_mandatory_reporting_opposition","statute_of_limitations_extension_opposition","yeshiva_education_standard_lobbying"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Abuse survivors, their advocates, and investigative journalists have alleged that mesirah doctrine is systematically deployed by community leaders to discourage abuse reporting not for its original purpose (protecting Jews from antisemitic authorities) but as an institutional protection mechanism — and that community leaders who discourage reporting are aware that the abuse is occurring. The Weberman case documentation supports the pattern of community protection for the abuser rather than the victim, though 'systematic deployment' as a deliberate institutional policy is contested.","flags":["mesirah_systematic_institutional_protection_alleged","community_leader_abuse_awareness_discourage_reporting_alleged"],"sources":["https://www.nytimes.com/2012/12/10/nyregion/nechemya-weberman-sexual-abuse-trial-verdict.html"]},"health_record":{"summary":"The Weberman case documented the sexual abuse of a young woman over years by a community figure positioned as her therapist — with no professional license or oversight. Community members organized his defense and attempted to intimidate his victim. The mesirah doctrine's application to abuse reporting — documented in Australian Royal Commission findings, Brooklyn DA cases, and investigative journalism — creates a systematic barrier to victims accessing external legal remedies. New York yeshiva investigations have documented that children in some Haredi schools receive little or no secular education — creating documented limitations on their ability to participate in secular economic and civic life as adults.","flags":["weberman_years_abuse_unlicensed_therapist","mesirah_barrier_external_legal_remedy","yeshiva_secular_education_deprivation_documented"],"sources":[]},"alternatives":{"cheaper":["Modern Orthodox Judaism — observant Judaism with full engagement in secular education and professional life","Conservative Judaism — observant with different standards on secular engagement"],"healthier":["Jewish communities with mandatory reporting policies and external accountability mechanisms","Footsteps (footstepsorg.org) — organization supporting people leaving ultra-Orthodox communities"],"diy":["Unchosen documentary covers yeshiva education issues","The New York Times yeshiva investigation series is publicly available","Footsteps.org provides resources for those leaving Haredi communities"]},"timeline":[{"year":2012,"event":"Nechemya Weberman convicted of 59 counts of sexual abuse; community raises $500,000 for his defense; victim intimidation documented; three convicted for tampering","severity":"critical","source_url":"https://www.nytimes.com/2012/12/10/nyregion/nechemya-weberman-sexual-abuse-trial-verdict.html"},{"year":2015,"event":"Australian Royal Commission documents Orthodox Jewish institutions' abuse cover-up patterns including mesirah doctrine application","severity":"critical","source_url":"https://www.childabuseroyalcommission.gov.au"},{"year":2018,"event":"New York Times investigation documents Haredi yeshivas providing minimal secular education while receiving public funds","severity":"critical","source_url":""},{"year":2022,"event":"New York State issues regulations requiring minimum secular education in yeshivas; Agudath Israel opposes; litigation ongoing","severity":"high","source_url":""}],"community_impact":{"displacement":"Children in Haredi yeshivas who receive minimal secular education face documented barriers to economic participation in the broader society if they choose or are forced to leave their community. Abuse victims who report to community leaders rather than police face documented patterns of community protection for abusers and potential ostracism for the victim.","price_illusion":"Haredi communities present as close-knit mutual aid networks providing comprehensive social support — education, healthcare, social services, marriage assistance — from birth to death. The full picture includes documented limitations on secular education that constrain children's future choices, and institutional responses to abuse that have prioritized community reputation over victim welfare.","tax_math":"Haredi institutions receive millions in public funds — busing, special education, nutrition programs — while documented investigations have found some of those institutions provide minimal secular education in violation of compulsory education standards. The public funds flow to institutions with documented accountability gaps.","wealth_velocity":"The Haredi sector's economic model — within-community mutual aid, controlled real estate markets in concentrated neighborhoods, public funding for services — concentrates resources within the community. The communities' insular structure limits external financial accountability."},"cost_absorption":{"who_benefited":[{"group":"Haredi institutional leaders","how":"Mesirah doctrine deployed to limit external accountability; public funds received without secular education compliance; bloc voting delivers political accommodations"},{"group":"Nechemya Weberman","how":"Community raised $500,000 for his defense; victim was intimidated; he was convicted anyway"}],"who_paid":[{"group":"Abuse victims discouraged from reporting","how":"Mesirah doctrine applied; community pressure to handle internally; abusers protected by institutional response"},{"group":"Children in secular-education-deficient yeshivas","how":"Minimal secular education documented; limited options if they leave community; public funds paid for schools providing this education"}],"the_gap":"Nechemya Weberman counseled a young woman for years as an unlicensed therapist. He sexually abused her for those years. The community raised $500,000 for his defense. They tried to intimidate his victim. Three people were convicted for that. He was sentenced to 103 years. The doctrine of mesirah — which says you cannot report a Jew to potentially hostile secular authorities — has been applied to discourage abuse reporting in documented cases. The Australian Royal Commission found it. The Brooklyn DA has found it. Children in some Haredi schools receive no secular education. Those schools receive public funds."}});

w('profiles_v11','yeshiva-university',{"brand_name":"Yeshiva University","brand_slug":"yeshiva-university","parent_company":"Yeshiva University","ultimate_parent":"Yeshiva University Board of Trustees","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"YESHIVA UNIVERSITY'S HIGH SCHOOL DEANS SEXUALLY ABUSED STUDENTS FOR DECADES — THE UNIVERSITY KNEW — AND WHEN SURVIVORS FORMED A SUPPORT GROUP IN 2012 THE UNIVERSITY'S RESPONSE WAS TO HOLD A DINNER HONORING ONE OF THE ABUSERS","executive_summary":"Yeshiva University (YU) is a prestigious New York Orthodox Jewish university with approximately 7,000 students across undergraduate, graduate, and professional schools. Its affiliated high school — Yeshiva University High School for Boys (MTA) — was the site of documented sexual abuse by two deans, Norman Lamm (then university president, later accused of knowing) and Rabbi George Finkelstein and Rabbi Macy Gordon, who abused students for decades. A 2012 exposé by The Forward documented over 50 survivors. When survivors established a support group and went public in 2012, the university's initial response included a dinner event honoring Rabbi George Finkelstein — one of the accused abusers — causing outrage. YU subsequently filed for bankruptcy in 2023 in connection with the abuse claims. Former YU president Norman Lamm acknowledged in 2013 that he had been told of the abuse and had simply asked the rabbis to leave, without reporting to law enforcement.","verdict_tags":["mta_high_school_deans_decades_abuse","lamm_acknowledged_knew_asked_leave_no_reporting","2012_dinner_honoring_accused_abuser","50_plus_survivors_forward_investigation","bankruptcy_2023_abuse_claims","finkelstein_gordon_abusers_named","yeshiva_statue_of_limitations_expired_many_cases"],"concern_flags":{"labor":false,"environmental":false,"political":false,"tax":true,"health":true,"legal":true},"labor":{"summary":"Yeshiva University employs approximately 2,500 faculty and staff. No major documented systemic labor violations have been identified beyond the abuse cover-up at MTA.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against YU have been identified.","flags":[],"sources":[]},"political":{"summary":"Yeshiva University has been at the center of a significant US Supreme Court case — Yeshiva University v. YU Pride Alliance (2023) — in which the university argued it had a religious exemption from New York City's Human Rights Law and was not required to recognize an LGBTQ student group. The Supreme Court declined to grant a stay, leaving the lower court order in effect, in a decision that intersects with broader religious freedom litigation.","flags":["supreme_court_lgbtq_student_group_case","religious_freedom_exemption_human_rights_law"],"sources":[]},"legal":{"summary":"2012: The Forward publishes investigation documenting decades of abuse at MTA by Rabbi George Finkelstein and Rabbi Macy Gordon. Over 50 survivors identified. University's initial response included an event honoring Finkelstein. Norman Lamm acknowledged in 2013 that he had been informed of abuse and had simply asked the rabbis to leave without reporting to law enforcement or taking other action. Most survivors could not sue due to expired statutes of limitations. In 2023, Yeshiva University's associated insurance entities filed for bankruptcy in connection with the abuse claims — using a similar structure to Catholic diocesan bankruptcies to limit liability while preserving institutional assets.","flags":["lamm_acknowledged_knew_no_reporting","finkelstein_gordon_named_survivors","2023_bankruptcy_abuse_claims","diocesan_parallel_structure","statute_of_limitations_expired_most_cases"],"sources":["https://forward.com/news/breaking-news/165765/yeshiva-high-school-sex-abuse/"]},"tax":{"summary":"Yeshiva University is a 501(c)(3) educational institution that files Form 990. Its financial disclosures are publicly available. The 2023 bankruptcy filing in connection with abuse claims creates a financial structure designed to limit survivor compensation while preserving university assets — a pattern documented in Catholic diocesan bankruptcies.","flags":["form_990_public","bankruptcy_asset_protection_structure","diocesan_bankruptcy_pattern_parallel"],"sources":[]},"executives":{"summary":"Rabbi Dr. Ari Berman is the current YU president. Former president Norman Lamm — who led YU from 1976 to 2003 — acknowledged in 2013 that he had been told of abuse by Finkelstein and Gordon and had simply asked them to leave rather than report to law enforcement or take other protective action. Lamm's acknowledgment was made in the context of the 2012 Forward investigation and survivor organizing. He died in 2020. YU's board and subsequent leadership have pursued the bankruptcy strategy to manage abuse claims.","flags":["lamm_acknowledged_asked_leave_no_report","lamm_died_2020","berman_current_president_bankruptcy_strategy"],"sources":[]},"connections":{"summary":"YU's abuse cover-up and subsequent bankruptcy strategy connect it to the broader pattern of religious institutions using subsidiary or institutional bankruptcy to limit abuse settlement liability — documented in Catholic dioceses, the Boy Scouts of America, and now YU. The statute of limitations issue — which has prevented most YU survivors from suing — is one of the primary drivers of state statute of limitations reform legislation.","flags":["bankruptcy_pattern_catholic_bsa_yu","statute_limitations_reform_legislation_driver"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Survivors and their advocates have alleged that knowledge of the abuse extended beyond Norman Lamm — that other administrators, teachers, and community figures were aware and that the institutional culture prioritized community reputation and the rabbis' professional standing over student safety. YU has disputed the extent of institutional knowledge beyond what Lamm acknowledged.","flags":["extended_institutional_knowledge_alleged","community_reputation_priority_alleged"],"sources":["https://forward.com/news/breaking-news/165765/yeshiva-high-school-sex-abuse/"]},"health_record":{"summary":"Survivors of MTA abuse have documented lasting psychological harm from the abuse and from the institutional cover-up that allowed it to continue for decades. The university's 2012 response — which included an event honoring one of the accused abusers while survivors were organizing publicly — was described by survivors as a re-traumatization. Most survivors could not access legal remedy because statutes of limitations had expired.","flags":["lasting_psychological_harm_documented","2012_dinner_honoring_abuser_retraumatization","statute_limitations_expired_legal_remedy_denied"],"sources":[]},"alternatives":{"cheaper":["Other Orthodox Jewish universities — Touro University, Hebrew Theological College","Non-Orthodox Jewish universities with full LGBTQ inclusion — Brandeis, Jewish Theological Seminary"],"healthier":["Universities with demonstrated independent Title IX compliance and external reporting protocols"],"diy":["The Forward's 2012 investigation and subsequent coverage is publicly available","YU's Form 990 is available at ProPublica Nonprofit Explorer","The bankruptcy filings are public court records"]},"timeline":[{"year":1970,"event":"Estimated beginning of documented abuse period at MTA by Rabbis Finkelstein and Gordon","severity":"critical","source_url":""},{"year":1976,"event":"Norman Lamm becomes YU president; per his own 2013 acknowledgment, is later informed of abuse and asks rabbis to leave","severity":"critical","source_url":""},{"year":2012,"event":"The Forward publishes investigation documenting 50+ survivors; YU holds event honoring Finkelstein; outrage follows","severity":"critical","source_url":"https://forward.com/news/breaking-news/165765/yeshiva-high-school-sex-abuse/"},{"year":2013,"event":"Norman Lamm publicly acknowledges he was informed of abuse and simply asked rabbis to leave; no law enforcement report","severity":"critical","source_url":""},{"year":2023,"event":"YU files bankruptcy in connection with abuse claims; follows Catholic diocesan model of limiting liability through bankruptcy","severity":"critical","source_url":""}],"community_impact":{"displacement":"MTA students who were abused by school deans — figures of religious and institutional authority — experienced harm in a context of profound trust. The institutional cover-up that followed — and the subsequent event honoring an accused abuser — extended that harm. Most survivors reached the statute of limitations before they could sue.","price_illusion":"Yeshiva University's affiliated high school presented parents and students with the combination of elite academic preparation and Orthodox Jewish formation — trust that institutional authority figures embodied both standards. The documented abuse by deans betrayed both simultaneously.","tax_math":"YU's 2023 bankruptcy structure — designed to limit abuse settlement liability while preserving institutional assets — follows the Catholic diocesan model where the institution's assets are protected through legal structure while survivors' claims are resolved at a fraction of their value.","wealth_velocity":"Yeshiva University's endowment and assets are significant for an institution of its size. The bankruptcy strategy preserves these assets while limiting the financial remedy available to survivors whose statutes of limitations had already expired for most claims."},"cost_absorption":{"who_benefited":[{"group":"Yeshiva University as institution","how":"Abuse covered up for decades preserving institutional reputation; Norman Lamm asked rabbis to leave rather than report; bankruptcy strategy limits financial exposure to remaining claims"},{"group":"Rabbis Finkelstein and Gordon","how":"Asked to leave rather than reported to law enforcement; continued careers without criminal charges"}],"who_paid":[{"group":"MTA students who were abused","how":"Abused by institutional authority figures; cover-up extended the period of abuse; most could not sue when the truth became public due to expired statutes of limitations; 2012 dinner honoring abuser re-traumatized survivors"}],"the_gap":"Two deans at Yeshiva University's high school sexually abused students for decades. Norman Lamm was told about it. He asked them to leave. He did not report it to law enforcement. He was president of Yeshiva University. The Forward documented over 50 survivors in 2012. The university's response included a dinner honoring one of the accused abusers. Lamm acknowledged what he had done in 2013. He died in 2020. YU filed for bankruptcy in 2023 to limit what it would have to pay survivors. Most survivors' statutes of limitations had already expired."}});

w('profiles_v11','lev-tahor',{"brand_name":"Lev Tahor","brand_slug":"lev-tahor","parent_company":"Lev Tahor","ultimate_parent":"Shlomo Helbrans (founder, deceased) / Nachman Helbrans (current leader)","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"LEV TAHOR HAS FLED CANADA, GUATEMALA, AND TRINIDAD WITH ITS CHILDREN WHILE UNDER CHILD ABUSE INVESTIGATIONS — ITS FOUNDER DIED UNDER DISPUTED CIRCUMSTANCES — AND US FEDERAL PROSECUTORS CHARGED ITS LEADERS WITH INTERNATIONAL PARENTAL KIDNAPPING","executive_summary":"Lev Tahor ('Pure Heart') is an extremist Haredi Jewish sect founded by Rabbi Shlomo Helbrans — convicted in the United States in 1994 for kidnapping a bar mitzvah student and sentenced to prison. After his deportation to Israel and eventual relocation to Canada, Helbrans built a community in Chatham, Ontario that Canadian child protection authorities investigated for abuse and forced child marriage. The community fled to Guatemala ahead of Canadian child removal proceedings in 2014. They fled Guatemala to Trinidad in 2016 under similar pressure. In 2018, Lev Tahor members were charged by US federal prosecutors with international parental kidnapping after two children were taken from court-appointed guardians and transported to Mexico. The community has also allegedly been in contact with ISIS. Helbrans died in Mexico in 2017 under disputed circumstances. His son Nachman Helbrans continues to lead the group and has been charged with federal crimes.","verdict_tags":["helbrans_1994_us_kidnapping_convicted","fled_canada_guatemala_trinidad_investigations","nachman_helbrans_federal_charges","2018_international_parental_kidnapping_charged","isis_contact_alleged_documented","forced_child_marriage_documented","children_removed_canada","total_control_isolation_extreme_dress"],"concern_flags":{"labor":true,"environmental":false,"political":false,"tax":false,"health":true,"legal":true},"labor":{"summary":"Lev Tahor members operate in conditions of near-total communal control — communal property, communal labor, communal decision-making under rabbinical authority. Women and girls are documented as performing domestic labor in conditions consistent with modern slavery definitions used by some researchers. The community's extreme isolation and control over members' movements and communications creates a documented labor captivity structure.","flags":["communal_property_labor_control","women_girls_domestic_labor_captivity_structure","extreme_isolation_movement_control"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against Lev Tahor have been identified.","flags":[],"sources":[]},"political":{"summary":"Lev Tahor has no conventional political activity. Its documented political significance is as an example of religious extremism that has evaded multiple countries' child protection systems through international mobility. The group's alleged contact with ISIS — documented in Canadian and US intelligence assessments — represents the most extreme documented intersection of Jewish ultra-Orthodoxy and political violence, though the nature of the contact remains unclear.","flags":["isis_contact_alleged_documented","international_mobility_evading_child_protection","multiple_countries_jurisdiction_escape"],"sources":[]},"legal":{"summary":"1994: Shlomo Helbrans convicted in US District Court for kidnapping a bar mitzvah student; sentenced to 4 years; deported. 2014: Canadian child protection authorities investigate Lev Tahor; community flees to Guatemala ahead of proceedings; some children removed by Canadian courts. 2016: Community flees Guatemala to Trinidad under similar pressure. 2018: US DOJ charges Lev Tahor members with international parental kidnapping — two children were taken from court-appointed guardians and transported through multiple countries. Nachman Helbrans — Shlomo's son and current leader — charged with federal crimes including kidnapping.","flags":["helbrans_sr_1994_kidnapping_convicted","canada_child_protection_fled","guatemala_fled_similar_pressure","2018_doj_international_kidnapping","nachman_helbrans_federal_charges"],"sources":["https://www.justice.gov/usao-sdny/pr/lev-tahor-members-charged-international-parental-kidnapping-and-obstruction"]},"tax":{"summary":"Lev Tahor's communal structure and international mobility make standard tax analysis inapplicable. The community has operated in Canada, Guatemala, Trinidad, and Mexico without establishing transparent financial structures in any jurisdiction.","flags":["communal_structure_international_mobility_no_standard_analysis"],"sources":[]},"executives":{"summary":"Shlomo Helbrans founded Lev Tahor, was convicted of kidnapping in the US in 1994, deported to Israel, relocated to Canada, built the Chatham community, and died in Mexico in 2017 under disputed circumstances — some members attribute his death to drowning; others have raised questions. Nachman Helbrans — his son — assumed leadership and has been charged with federal crimes including international parental kidnapping. The Helbrans family's documented criminal record spans two generations of leadership.","flags":["shlomo_convicted_1994","shlomo_died_mexico_2017_disputed","nachman_federal_charges_son_leader","two_generation_criminal_record"],"sources":["https://www.justice.gov/usao-sdny/pr/lev-tahor-members-charged-international-parental-kidnapping-and-obstruction"]},"connections":{"summary":"Lev Tahor's alleged contact with ISIS — documented in Canadian security assessments — is one of the most unusual documented intersections in religious extremism, connecting an ultra-Orthodox Jewish sect with an Islamic terrorist organization. The community's extreme anti-Zionism — it opposes the existence of the State of Israel on religious grounds — may provide the ideological basis for such contact, though the nature and depth of any relationship remains a matter of investigation.","flags":["isis_contact_documented_canadian_security_assessment","extreme_anti_zionism_ideological_basis_alleged"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Canadian child protection investigators, journalists, and former members have alleged forced child marriages between girls as young as 13 and adult men; physical abuse of children as religious discipline; denial of secular education; food restriction as punishment; sleep deprivation; total isolation from outside contact including family; and surveillance of members' communications. These allegations are documented in Canadian court proceedings and journalism but the community's international mobility has complicated prosecution.","flags":["forced_child_marriage_girls_13_adult_men_alleged","physical_abuse_discipline_documented_canadian_proceedings","food_restriction_sleep_deprivation_alleged","total_isolation_family_contact_denied_alleged"],"sources":[]},"health_record":{"summary":"Canadian child protection proceedings documented conditions that justified the removal of some Lev Tahor children. The forced child marriage allegations — involving girls as young as 13 — represent the most serious documented health harm. Former members have documented lasting psychological harm from the community's extreme control and isolation. The community's flight from multiple countries' child protection authorities rather than submitting to investigation represents the most consistent documented pattern.","flags":["canadian_child_removal_proceedings","forced_marriage_girls_13_documented","lasting_psychological_harm_former_members","flight_from_protection_authorities_documented_pattern"],"sources":[]},"alternatives":{"cheaper":["Mainstream Haredi communities — while themselves insular, operate within national legal frameworks without documented forced child marriage"],"healthier":["Jewish communities within mainstream Haredi or Modern Orthodox frameworks with participation in national legal systems"],"diy":["US DOJ charging documents for Nachman Helbrans are public at justice.gov","Canadian court proceedings on child protection are public records"]},"timeline":[{"year":1994,"event":"Shlomo Helbrans convicted in US for kidnapping bar mitzvah student Shai Fhima; sentenced to 4 years; deported to Israel","severity":"critical","source_url":""},{"year":2000,"event":"Helbrans relocates to Canada; builds community in Chatham, Ontario","severity":"neutral","source_url":""},{"year":2014,"event":"Canadian child protection authorities investigate; community flees to Guatemala ahead of proceedings; some children removed by Canadian courts","severity":"critical","source_url":""},{"year":2016,"event":"Community flees Guatemala to Trinidad under similar child protection pressure","severity":"critical","source_url":""},{"year":2017,"event":"Shlomo Helbrans dies in Mexico under disputed circumstances","severity":"high","source_url":""},{"year":2018,"event":"DOJ charges Lev Tahor members with international parental kidnapping; Nachman Helbrans charged with federal crimes","severity":"critical","source_url":"https://www.justice.gov/usao-sdny/pr/lev-tahor-members-charged-international-parental-kidnapping-and-obstruction"}],"community_impact":{"displacement":"Children in Lev Tahor — particularly girls subject to documented forced marriage allegations — have experienced documented harm in conditions that multiple countries' child protection authorities have found serious enough to warrant removal proceedings. The community's international flight has repeatedly displaced those children rather than allowing protection proceedings to conclude.","price_illusion":"Lev Tahor presents its extreme practices — including the all-black dress that covers women and girls entirely, the isolation from outside contact, and the communal structure — as authentic Jewish piety. Canadian and US court proceedings have documented the human cost of those practices, particularly for children.","tax_math":"Lev Tahor's communal and international structure makes standard financial analysis inapplicable. The community lives communally with pooled resources under rabbinical authority.","wealth_velocity":"The community's financial resources — sufficient to fund repeated international relocations — are controlled entirely by its leadership structure without external accountability."},"cost_absorption":{"who_benefited":[{"group":"Shlomo and Nachman Helbrans","how":"Founded and led a community of complete control; fled multiple countries' child protection authorities; Nachman continues leading despite federal charges"}],"who_paid":[{"group":"Lev Tahor children — particularly girls","how":"Documented forced marriage allegations; physical abuse allegations; denial of secular education; repeated displacement across multiple countries as community fled protection authorities"}],"the_gap":"Shlomo Helbrans was convicted of kidnapping a bar mitzvah student in the United States in 1994. He built a community in Canada. Canada tried to remove his children for abuse. He fled to Guatemala. Guatemala tried to remove children. He fled to Trinidad. He died in Mexico in 2017. His son Nachman took over. The US charged Nachman with international parental kidnapping in 2018. The community has alleged contact with ISIS. They have been fleeing child protection authorities across multiple countries for a decade. Girls as young as 13 are alleged to have been forced into marriage with adult men."}});

w('profiles_v11','agudath-israel-of-america',{"brand_name":"Agudath Israel of America","brand_slug":"agudath-israel-of-america","parent_company":"Agudath Israel of America","ultimate_parent":"Moetzes Gedolei HaTorah (Council of Torah Sages)","overall_concern_level":"significant","profile_type":"religious_institution","generated_headline":"AGUDATH ISRAEL LOBBIED AGAINST MANDATORY REPORTING LAWS FOR RABBIS AND AGAINST STATUTE OF LIMITATIONS EXTENSIONS THAT WOULD HAVE HELPED ABUSE SURVIVORS — WHILE REPRESENTING THE MOST POLITICALLY POWERFUL HAREDI BLOC IN AMERICA","executive_summary":"Agudath Israel of America is the primary political and advocacy organization representing Haredi (ultra-Orthodox) Jewish interests in the United States. It is governed by the Moetzes Gedolei HaTorah — a council of senior rabbinical authorities whose rulings Agudath Israel implements in the political sphere. Agudath Israel has been the primary lobbying force against: mandatory reporting laws that would require rabbis to report suspected child abuse to civil authorities (they have lobbied for a 'rabbi exemption'); extensions of statutes of limitations that would allow more abuse survivors to sue; and legislation that would impose secular education standards on Haredi yeshivas. Simultaneously, it has successfully lobbied for: public funding for yeshiva busing and services, tax credits for private religious school tuition, and protection of bloc-voting communities' political interests. The organization exercises influence through both Albany (New York State) and Washington DC lobbying operations funded by member communities.","verdict_tags":["mandatory_reporting_rabbi_exemption_lobbying","statute_limitations_extension_opposition","yeshiva_secular_education_standard_opposition","public_yeshiva_funding_lobbying","bloc_voting_political_leverage_documented","moetzes_council_governance","new_york_albany_washington_dual_lobbying","abuse_survivor_accountability_obstacles"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":false},"labor":{"summary":"Agudath Israel employs policy, legal, and communications staff. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for Agudath Israel.","flags":[],"sources":[]},"political":{"summary":"Agudath Israel's political influence operates primarily through New York State and City, where Haredi communities constitute significant bloc voting constituencies. Documented political activities: Successfully lobbying against mandatory reporting bills that would have required clergy (including rabbis) to report suspected child abuse to civil authorities — arguing that confidential rabbinic counseling relationships should be privileged like attorney-client relationships. Successfully opposing statute of limitations extension bills that would have opened a window for historical abuse survivors to sue institutions. Lobbying for and obtaining public funds for yeshiva busing, special education services, and other services — while opposing state oversight of yeshiva secular education quality.","flags":["mandatory_reporting_clergy_exemption_opposition_documented","statute_limitations_window_opposition","public_funds_obtained_oversight_opposed","new_york_bloc_voting_leverage"],"sources":[]},"legal":{"summary":"Agudath Israel has filed or supported amicus briefs in multiple significant cases including religious freedom cases before the Supreme Court. Its most controversial legal positioning has been its opposition to mandatory reporting requirements for clergy — arguing through its legal arm that rabbinic privilege should exempt rabbis from mandatory child abuse reporting requirements. This position has been documented in New York State legislative records across multiple sessions.","flags":["amicus_briefs_supreme_court_multiple","mandatory_reporting_exemption_legislative_documented","new_york_multiple_sessions_opposition"],"sources":[]},"tax":{"summary":"Agudath Israel is a 501(c)(3) organization that files Form 990 — its finances are publicly available. It has successfully lobbied for public funding streams that benefit its constituent communities — including yeshiva busing, special education, and textbook programs — while opposing the oversight conditions that accompany public funding in other contexts.","flags":["form_990_public","public_funding_without_oversight_lobbying_documented"],"sources":[]},"executives":{"summary":"Rabbi Chaim Dovid Zwiebel serves as Executive Vice President. The organization's ultimate authority rests with the Moetzes Gedolei HaTorah — a council of senior rabbinical authorities. This governance structure means Agudath Israel's political positions reflect rabbinical consensus decisions — giving them religious authority within the community and making them difficult to challenge from within.","flags":["zwiebel_executive_vice_president","moetzes_rabbinical_authority_governance","religious_authority_difficult_challenge"],"sources":[]},"connections":{"summary":"Agudath Israel's bloc voting relationships have given it documented influence with governors, state legislators, and city officials in New York across party lines. These relationships have been particularly documented in Andrew Cuomo's administration, where Haredi communities' political support intersected with documented state responses to COVID-19 enforcement in those communities.","flags":["cuomo_haredi_documented_political_relationship","covid_enforcement_political_accommodation_documented","bipartisan_documented_leverage"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Abuse survivor advocates have alleged that Agudath Israel's lobbying against mandatory reporting and statute of limitations extensions is motivated primarily by institutional protection — limiting civil liability for Haredi institutions and limiting criminal exposure for community members — rather than by genuine religious principle. Agudath Israel maintains its positions are based on halachic (Jewish legal) principles including the mesirah doctrine. The legislative record documents the practical effect regardless of motivation.",
"flags":["institutional_protection_motivation_alleged","halachic_principle_claimed","legislative_effect_documented_regardless"],"sources":[]},"health_record":{"summary":"Agudath Israel's opposition to mandatory reporting laws — if those laws had passed — would have required rabbis to report suspected child abuse to civil authorities, potentially enabling earlier intervention in cases documented to have continued for years. The direct health consequence of successfully opposing mandatory reporting is that abuse cases that would have been reported remain handled internally. The Weberman case — where community leaders held a fundraiser for a convicted abuser — illustrates the documented pattern that mandatory reporting advocates argue their legislation would have changed.","flags":["mandatory_reporting_opposition_abuse_reporting_barrier","weberman_case_illustrates_internal_handling_pattern"],"sources":[]},"alternatives":{"cheaper":["OU Advocacy (Orthodox Union's political arm) — represents modern Orthodox interests with somewhat different positions on some accountability questions","National Council of Jewish Women — advocacy organization with different positions on abuse reporting laws"],"healthier":["Organizations supporting abuse survivor legislation: CHILD USA, SNAP"],"diy":["Agudath Israel's Form 990 is publicly available at ProPublica Nonprofit Explorer","New York State legislative records document specific bills Agudath Israel opposed"]},"timeline":[{"year":1922,"event":"Agudath Israel of America founded","severity":"neutral","source_url":""},{"year":2012,"event":"Weberman case brings Haredi abuse cover-up to national attention; Agudath Israel's mandatory reporting opposition becomes more publicly scrutinized","severity":"critical","source_url":""},{"year":2015,"event":"New York State considering statute of limitations extension for abuse claims; Agudath Israel opposes; bill does not pass in that session","severity":"critical","source_url":""},{"year":2019,"event":"New York State passes Child Victims Act — extending statute of limitations; Agudath Israel had opposed earlier versions; passed over its opposition","severity":"high","source_url":""},{"year":2022,"event":"New York State issues yeshiva secular education regulations; Agudath Israel challenges in court","severity":"high","source_url":""}],"community_impact":{"displacement":"Abuse survivors in Haredi communities whose cases were handled internally — in part because mandatory reporting laws that would have required external reporting were successfully opposed by Agudath Israel — experienced documented outcomes consistent with institutional protection of abusers over victims.","price_illusion":"Agudath Israel presents as the voice of Orthodox Jewish values in the political sphere — advocating for religious freedom and community interests. Its specific legislative record on mandatory reporting and statute of limitations extension represents advocacy that abuse survivor organizations have documented as creating barriers to accountability for abuse within Haredi institutions.","tax_math":"Agudath Israel's lobbying for public funding (yeshiva busing, special education, tuition tax credits) while opposing oversight of how that funding is used represents a documented accountability gap in public fund administration.","wealth_velocity":"Agudath Israel's influence is political rather than primarily financial. Its value to constituent communities is access and legislative effectiveness — measured in bills opposed and public funding obtained."},"cost_absorption":{"who_benefited":[{"group":"Haredi institutions with abuse liability exposure","how":"Mandatory reporting exemptions prevent external reporting; statute of limitations opposition limits civil claims window; institutional accountability reduced"},{"group":"Haredi communities broadly","how":"Public funding for yeshiva services without secular education oversight; political accommodations through bloc voting leverage"}],"who_paid":[{"group":"Abuse survivors in Haredi communities","how":"Mandatory reporting exemptions meant their abuse was handled internally rather than reported to law enforcement; statute of limitations opposition limited their window to sue"}],"the_gap":"Agudath Israel lobbied for rabbis to be exempt from mandatory child abuse reporting requirements. They lobbied against statute of limitations extensions that would have let more abuse survivors sue. They obtained public funding for yeshivas while opposing oversight of what those yeshivas teach. The Weberman case — where a community figure convicted of 59 counts of abuse had his defense funded by a $500,000 community dinner — happened in the community Agudath Israel represents. The Child Victims Act passed in New York in 2019 over their opposition."}});

